import { forwardRef, type ElementType, type ReactElement, type ReactNode, type Ref } from 'react';
import { cn, vc } from '../../utils/cn';
import type { PolymorphicComponentPropsWithRef } from '../../utils/polymorphic';
import styles from './Button.module.css';

export type ButtonVariant =
  | 'primary'
  | 'secondary'
  | 'outline'
  | 'ghost'
  | 'destructive';

export type ButtonSize = 'sm' | 'md' | 'lg';

export interface ButtonOwnProps {
  variant?: ButtonVariant;
  size?: ButtonSize;
  disabled?: boolean;
  loading?: boolean;
  leftIcon?: ReactNode;
  rightIcon?: ReactNode;
  fullWidth?: boolean;
  className?: string;
  children?: ReactNode;
  'data-testid'?: string;
}

export type ButtonProps<C extends ElementType = 'button'> =
  PolymorphicComponentPropsWithRef<C, ButtonOwnProps>;

function Spinner({ size }: { size: ButtonSize }) {
  const px = size === 'sm' ? 12 : size === 'lg' ? 18 : 14;
  return (
    <svg
      className={styles.spinner}
      width={px}
      height={px}
      viewBox="0 0 24 24"
      fill="none"
      aria-hidden="true"
    >
      <circle
        cx="12"
        cy="12"
        r="10"
        stroke="currentColor"
        strokeOpacity="0.25"
        strokeWidth="3"
      />
      <path
        d="M22 12A10 10 0 0 0 12 2"
        stroke="currentColor"
        strokeWidth="3"
        strokeLinecap="round"
      />
    </svg>
  );
}

function ButtonImpl(
  {
    as,
    variant = 'primary',
    size = 'md',
    disabled = false,
    loading = false,
    leftIcon,
    rightIcon,
    fullWidth = false,
    className,
    children,
    onClick,
    type,
    'data-testid': dataTestId = 'tatva-button',
    ...rest
  }: ButtonProps,
  ref: Ref<Element>,
) {
  const Component = (as ?? 'button') as ElementType;
  const isNativeButton = Component === 'button';
  const isInteractionBlocked = disabled || loading;

  return (
    <Component
      ref={ref}
      className={cn(
        styles.button,
        vc(styles, 'variant', variant),
        vc(styles, 'size', size),
        fullWidth && styles.fullWidth,
        loading && styles.loading,
        className,
      )}
      data-testid={dataTestId}
      data-variant={variant}
      data-size={size}
      aria-disabled={isInteractionBlocked || undefined}
      aria-busy={loading || undefined}
      disabled={isNativeButton ? disabled : undefined}
      type={isNativeButton ? (type ?? 'button') : type}
      onClick={(e: React.MouseEvent) => {
        if (isInteractionBlocked) {
          e.preventDefault();
          e.stopPropagation();
          return;
        }
        (onClick as ((e: React.MouseEvent) => void) | undefined)?.(e);
      }}
      {...rest}
    >
      {loading && <Spinner size={size} />}
      {!loading && leftIcon && (
        <span className={styles.icon} aria-hidden="true">
          {leftIcon}
        </span>
      )}
      <span className={styles.label}>{children}</span>
      {!loading && rightIcon && (
        <span className={styles.icon} aria-hidden="true">
          {rightIcon}
        </span>
      )}
    </Component>
  );
}

/**
 * Button — versatile action element. Polymorphic (renders as any element via `as`).
 * See ButtonProps for the full API.
 */
export const Button = forwardRef(ButtonImpl) as unknown as <
  C extends ElementType = 'button',
>(
  props: ButtonProps<C>,
) => ReactElement | null;

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--tatva-space-2);
  font-family: var(--tatva-font-family);
  font-weight: var(--tatva-font-weight-medium);
  border-radius: var(--tatva-radius-md);
  border: 1px solid transparent;
  cursor: pointer;
  user-select: none;
  transition:
    background-color var(--tatva-transition-fast),
    border-color var(--tatva-transition-fast),
    color var(--tatva-transition-fast),
    box-shadow var(--tatva-transition-fast),
    transform var(--tatva-transition-fast);
  text-decoration: none;
  line-height: var(--tatva-line-height-tight);
  white-space: nowrap;
}

.button:focus-visible {
  outline: none;
  box-shadow: 0 0 0 3px var(--tatva-color-primary-200);
  border-color: var(--tatva-color-primary-500);
}

.button:disabled,
.button[aria-disabled='true'] {
  cursor: not-allowed;
  opacity: 0.55;
}

.button:not(:disabled):not([aria-disabled='true']):active {
  transform: translateY(1px);
}

/* --- Sizes --- */
.sizeSm {
  height: 32px;
  padding: 0 var(--tatva-space-3);
  font-size: var(--tatva-font-size-sm);
}
.sizeMd {
  height: 40px;
  padding: 0 var(--tatva-space-4);
  font-size: var(--tatva-font-size-md);
}
.sizeLg {
  height: 48px;
  padding: 0 var(--tatva-space-6);
  font-size: var(--tatva-font-size-lg);
}

/* --- Variants --- */
.variantPrimary {
  background-color: var(--tatva-color-primary-600);
  color: #ffffff;
}
.variantPrimary:not(:disabled):not([aria-disabled='true']):hover {
  background-color: var(--tatva-color-primary-700);
}

.variantSecondary {
  background-color: var(--tatva-color-neutral-100);
  color: var(--tatva-color-fg);
  border-color: var(--tatva-color-border);
}
.variantSecondary:not(:disabled):not([aria-disabled='true']):hover {
  background-color: var(--tatva-color-neutral-200);
}

.variantOutline {
  background-color: transparent;
  color: var(--tatva-color-primary-700);
  border-color: var(--tatva-color-primary-500);
}
.variantOutline:not(:disabled):not([aria-disabled='true']):hover {
  background-color: var(--tatva-color-primary-50);
}

.variantGhost {
  background-color: transparent;
  color: var(--tatva-color-fg);
}
.variantGhost:not(:disabled):not([aria-disabled='true']):hover {
  background-color: var(--tatva-color-neutral-100);
}

.variantDestructive {
  background-color: var(--tatva-color-error);
  color: #ffffff;
}
.variantDestructive:not(:disabled):not([aria-disabled='true']):hover {
  filter: brightness(0.92);
}

/* --- Modifiers --- */
.fullWidth {
  width: 100%;
}

.loading {
  cursor: wait;
}

.icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  line-height: 0;
}

.label {
  display: inline-block;
}

.spinner {
  animation: tatva-btn-spin 0.7s linear infinite;
}

@keyframes tatva-btn-spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

export { Button } from './Button';
export type {
  ButtonProps,
  ButtonOwnProps,
  ButtonVariant,
  ButtonSize,
} from './Button';
